t.script:
            document.addEventListener('DOMContentLoaded', function() {
                var map = L.map('map').setView([-30.750, -57.983], 13);

                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                    attribution: '© OpenStreetMap'
                }).addTo(map);

                try {
                    var luminarias = ;
                    if (luminarias && luminarias.length > 0) {
                        luminarias.forEach(function(l){
                            if (l.lat && l.lng) {
                                L.marker([l.lat, l.lng])
                                .addTo(map)
                                .bindPopup(
                                    "" + (l.name || 'Sin nombre') + "
" +
                                    (l.direccion || '')
                                );
                            }
                        });
                        
                        // Opcional: Ajustar el mapa para mostrar todos los marcadores
                        var group = new L.featureGroup(luminarias.map(l => L.marker([l.lat, l.lng])));
                        map.fitBounds(group.getBounds());
                    }
                } catch (e) {
                    console.error("Error cargando luminarias:", e);
                }
            });
